import socket
import network
import ujson
import time
import ubinascii
import websocket

# WiFi credentials
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# Initialize WiFi
wlan = network.WLAN(network.STA_IF)
wlan.active(True)
wlan.connect(WIFI_SSID, WIFI_PASSWORD)

# Wait for connection
while not wlan.isconnected():
    time.sleep(1)

print("Connected to WiFi")
print("IP address:", wlan.ifconfig()[0])

# Create socket
server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
server_socket.bind((wlan.ifconfig()[0], 8080))
server_socket.listen(5)

print("WebSocket server listening on port 8080")

def handle_json_command(command):
    try:
        data = ujson.loads(command)
        action = data.get("action", "")
        
        if action == "turn_on":
            print("Turning device ON")
            # Add your device control logic here
            return {"status": "success", "action": "turn_on"}
        elif action == "turn_off":
            print("Turning device OFF")
            # Add your device control logic here
            return {"status": "success", "action": "turn_off"}
        else:
            return {"status": "error", "message": "Unknown action"}
    except Exception as e:
        return {"status": "error", "message": str(e)}

def websocket_server():
    while True:
        try:
            client_socket, client_address = server_socket.accept()
            print("Client connected from", client_address)
            
            # WebSocket handshake
            request = client_socket.recv(1024).decode('utf-8')
            if "WebSocket" in request:
                # Simple WebSocket handshake response
                key = request.split("Sec-WebSocket-Key: ")[1].split("\r\n")[0]
                response_key = ubinascii.b2a_base64(ubinascii.a2b_base64(key) + b"258EAFA5-E914-47DA-95CA-C5AB0DC85B11")
                response = (
                    "HTTP/1.1 101 Switching Protocols\r\n"
                    "Upgrade: websocket\r\n"
                    "Connection: Upgrade\r\n"
                    "Sec-WebSocket-Accept: " + response_key.decode('utf-8') + "\r\n\r\n"
                )
                client_socket.send(response.encode())
                
                # Main loop for receiving messages
                while True:
                    try:
                        data = client_socket.recv(1024)
                        if not data:
                            break
                        
                        # Parse WebSocket frame (simplified)
                        message = data[6:].decode('utf-8')  # Skip WebSocket headers
                        print("Received message:", message)
                        
                        # Handle JSON command
                        response_data = handle_json_command(message)
                        response_json = ujson.dumps(response_data)
                        
                        # Send response back to client
                        client_socket.send(b"\x81" + bytes([len(response_json)]) + response_json.encode())
                        
                    except Exception as e:
                        print("Error handling message:", e)
                        break
            else:
                client_socket.close()
                
        except Exception as e:
            print("Error accepting connection:", e)
            time.sleep(1)

# Start the WebSocket server
websocket_server()